long long solve(std::vector<std::vector<long long>> points) {
    const long long MOD = 1e9 + 7;
    map<long long, vector<long long>> y_to_x;
    for (const auto& p : points) {
        long long x = p[0], y = p[1];
        y_to_x[y].push_back(x);
    }

    for (auto& pair : y_to_x) {
        sort(pair.second.begin(), pair.second.end());
    }

    long long res = 0;
    for (auto it1 = y_to_x.begin(); it1 != y_to_x.end(); ++it1) {
        for (auto it2 = next(it1); it2 != y_to_x.end(); ++it2) {
